#include "pytorch_npu_helper.hpp"

at::Tensor conv_depthwise_2d_square_input_square_kernel_custom_impl_npu(
    const at::Tensor& x,
    const at::Tensor& weight,
    int64_t stride_h,
    int64_t stride_w,
    int64_t pad_h,
    int64_t pad_w,
    int64_t dilation_h,
    int64_t dilation_w,
    int64_t groups) {

    // Infer output size (only supports no padding, stride=1, dilation=1)
    TORCH_CHECK(x.dim() == 4, "x must be NCHW");
    TORCH_CHECK(weight.dim() == 4, "weight must be [C,1,kH,kW]");
    auto N = x.size(0);
    auto C = x.size(1);
    auto H = x.size(2);
    auto W = x.size(3);
    auto kH = weight.size(2);
    auto kW = weight.size(3);
    TORCH_CHECK(groups == C, "depthwise groups must equal channels");
    int64_t outH = H - kH + 1;
    int64_t outW = W - kW + 1;

    at::Tensor y = at::empty({N, C, outH, outW}, x.options());
    EXEC_NPU_CMD(aclnnConvDepthwise2dSquareInputSquareKernelCustom,
                 x, weight,
                 static_cast<int>(stride_h), static_cast<int>(stride_w),
                 static_cast<int>(pad_h), static_cast<int>(pad_w),
                 static_cast<int>(dilation_h), static_cast<int>(dilation_w),
                 static_cast<int>(groups),
                 y);
    return y;
}

